import{_ as i,o as t,c as a,a2 as s}from"./chunks/framework.DtwafDNl.js";const u=JSON.parse('{"title":"Diagnostics","description":"","frontmatter":{},"headers":[],"relativePath":"features/diagnostics.md","filePath":"features/diagnostics.md"}'),n={name:"features/diagnostics.md"};function l(r,e,o,c,h,d){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="diagnostics" tabindex="-1">Diagnostics <a class="header-anchor" href="#diagnostics" aria-label="Permalink to &quot;Diagnostics&quot;">​</a></h1><p>Diagnostics brings the main health checks for the phone system into one place. It shows whether core services are reachable, how long the system has been running, and whether the telephony layer can communicate with trunks and registered endpoints.</p><p>You can test trunk health, review SIP registration status, inspect recent call failures, and look at SIP traffic from the browser. This reduces the time spent switching between shell commands, logs, and separate monitoring tools when investigating call problems.</p><p>The page also includes resource usage and plain-English log viewing so you can quickly tell whether an issue looks like configuration, provider connectivity, service health, or server capacity.</p><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h2><ul><li>System health panel for ARI, AMI, Asterisk, PostgreSQL, Redis, and uptime</li><li>Trunk health testing</li><li>PJSIP qualify visibility</li><li>SIP registration status</li><li>Recent call failure analysis</li><li>SIP traffic inspector</li><li>Resource usage panel for CPU, memory, disk, active channels, and network I/O</li><li>Plain-English Asterisk log viewer</li><li>Grep-style log filtering</li></ul>',6)])])}const g=i(n,[["render",l]]);export{u as __pageData,g as default};
